#include<bits/stdc++.h>
using namespace std;

struct Mv {
    int x, y, g;
} ans[10], tmp[10];

int n;
int g[7][5];
int bk[10][7][5];

void save(int s) {
    for(int i = 0; i < 7; i++)
        for(int j = 0; j < 5; j++)
            bk[s][i][j] = g[i][j];
}
void load(int s) {
    for(int i = 0; i < 7; i++)
        for(int j = 0; j < 5; j++)
            g[i][j] = bk[s][i][j];
}

void fall() {
    for(int j = 0; j < 5; j++) {
        int p = 0;
        for(int i = 0; i < 7; i++) {
            if(g[i][j] != 0) {
                g[p][j] = g[i][j];
                if(p != i) g[i][j] = 0;
                p++;
            }
        }
        for(; p < 7; p++) g[p][j] = 0;
    }
}

bool elim() {
    bool mk[7][5] = {0};
    bool ok = 0;

    for(int i = 0; i < 7; i++) {
        for(int j = 0; j < 5; j++) {
            if(g[i][j] == 0) continue;
            int l = 1;
            while(j+l < 5 && g[i][j+l] == g[i][j]) l++;
            if(l >= 3) {
                for(int k = 0; k < l; k++) mk[i][j+k] = 1;
            }
            j += l - 1;
        }
    }

    for(int j = 0; j < 5; j++) {
        for(int i = 0; i < 7; i++) {
            if(g[i][j] == 0) continue;
            int l = 1;
            while(i+l < 7 && g[i+l][j] == g[i][j]) l++;
            if(l >= 3) {
                for(int k = 0; k < l; k++) mk[i+k][j] = 1;
            }
            i += l - 1;
        }
    }

    for(int i = 0; i < 7; i++)
        for(int j = 0; j < 5; j++)
            if(mk[i][j]) {
                g[i][j] = 0;
                ok = 1;
            }
    return ok;
}

void proc() {
    while(1) {
        fall();
        if(!elim()) break;
    }
}

bool empty() {
    for(int i = 0; i < 7; i++)
        for(int j = 0; j < 5; j++)
            if(g[i][j] != 0) return 0;
    return 1;
}

void mv(int x, int y, int d) {
    int nx = x + d;
    swap(g[y][x], g[y][nx]);
    proc();
}

bool prune() {
    int cnt[11] = {0};
    for(int i = 0; i < 7; i++)
        for(int j = 0; j < 5; j++)
            if(g[i][j] != 0) cnt[g[i][j]]++;
    for(int i = 1; i <= 10; i++)
        if(cnt[i] == 1 || cnt[i] == 2) return 1;
    return 0;
}

bool ok = 0;

void dfs(int s) {
    if(ok) return;
    if(empty()) {
        ok = 1;
        for(int i = 0; i < s; i++)
            ans[i] = tmp[i];
        return;
    }
    if(s == n) return;
    if(prune()) return;

    save(s);

    for(int x = 0; x < 5; x++) {
        for(int y = 0; y < 7; y++) {
            if(g[y][x] == 0) continue;

            if(x < 4 && g[y][x+1] != g[y][x]) {
                tmp[s] = {x, y, 1};
                mv(x, y, 1);
                dfs(s+1);
                load(s);
            }

            if(x > 0 && g[y][x-1] == 0) {
                tmp[s] = {x, y, -1};
                mv(x, y, -1);
                dfs(s+1);
                load(s);
            }
        }
    }
}

int main() {
    cin >> n;
    memset(g, 0, sizeof(g));

    for(int j = 0; j < 5; j++) {
        int i = 0, v;
        while(cin >> v && v != 0) {
            g[i][j] = v;
            i++;
        }
    }

    dfs(0);

    if(ok) {
        for(int i = 0; i < n; i++)
            cout << ans[i].x << " " << ans[i].y << " " << ans[i].g << endl;
    } else {
        cout << -1 << endl;
    }

    return 0;
}
